const e=JSON.parse('{"key":"v-32c37fbe","path":"/%E6%A1%86%E6%9E%B6/%E6%8C%81%E4%B9%85%E5%B1%82/03-MyBatis-Plus%EF%BC%88%E4%B8%80%EF%BC%89.html","title":"MyBatis-Plus（一）","lang":"zh-CN","frontmatter":{"date":"2021-09-10T00:00:00.000Z","category":["MyBatis"],"tag":["MyBatis"],"order":3,"description":"MyBatis-Plus（一） 一、MyBatis-Plus简介 1、简介 MyBatis-Plus（简称 MP）是一个 MyBatis的增强工具，在 MyBatis 的基础上只做增强不做改变，为简化开发、提高效率而生。 愿景 我们的愿景是成为 MyBatis 最好的搭档，就像魂斗罗中的 1P、2P，基友搭配，效率翻倍 2、特性 无侵入：只做增强不做改变，引入它不会对现有工程产生影响，如丝般顺滑 损耗小：启动即会自动注入基本 CURD，性能基本无损耗，直接面向对象操作 强大的 CRUD 操作：内置通用 Mapper、通用 Service，仅仅通过少量配置即可实现单表大部分CRUD 操作，更有强大的条件构造器，满足各类使用需求 支持 Lambda 形式调用：通过 Lambda 表达式，方便的编写各类查询条件，无需再担心字段写错 支持主键自动生成：支持多达 4 种主键策略（内含分布式唯一 ID 生成器 - Sequence），可自由配置，完美解决主键问题 支持 ActiveRecord 模式：支持 ActiveRecord 形式调用，实体类只需继承 Model 类即可进行强大的 CRUD 操作 支持自定义全局通用操作：支持全局通用方法注入（ Write once, use anywhere ） 内置代码生成器：采用代码或者 Maven 插件可快速生成 Mapper 、 Model 、 Service 、Controller 层代码，支持模板引擎，更有超多自定义配置等您来使用 内置分页插件：基于 MyBatis 物理分页，开发者无需关心具体操作，配置好插件之后，写分页等同于普通 List 查询 分页插件支持多种数据库：支持 MySQL、MariaDB、Oracle、DB2、H2、HSQL、SQLite、Postgre、SQLServer 等多种数据库 内置性能分析插件：可输出 SQL 语句以及其执行时间，建议开发测试时启用该功能，能快速揪出慢查询 内置全局拦截插件：提供全表 delete 、 update 操作智能分析阻断，也可自定义拦截规则，预防误操作","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E6%A1%86%E6%9E%B6/%E6%8C%81%E4%B9%85%E5%B1%82/03-MyBatis-Plus%EF%BC%88%E4%B8%80%EF%BC%89.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"MyBatis-Plus（一）"}],["meta",{"property":"og:description","content":"MyBatis-Plus（一） 一、MyBatis-Plus简介 1、简介 MyBatis-Plus（简称 MP）是一个 MyBatis的增强工具，在 MyBatis 的基础上只做增强不做改变，为简化开发、提高效率而生。 愿景 我们的愿景是成为 MyBatis 最好的搭档，就像魂斗罗中的 1P、2P，基友搭配，效率翻倍 2、特性 无侵入：只做增强不做改变，引入它不会对现有工程产生影响，如丝般顺滑 损耗小：启动即会自动注入基本 CURD，性能基本无损耗，直接面向对象操作 强大的 CRUD 操作：内置通用 Mapper、通用 Service，仅仅通过少量配置即可实现单表大部分CRUD 操作，更有强大的条件构造器，满足各类使用需求 支持 Lambda 形式调用：通过 Lambda 表达式，方便的编写各类查询条件，无需再担心字段写错 支持主键自动生成：支持多达 4 种主键策略（内含分布式唯一 ID 生成器 - Sequence），可自由配置，完美解决主键问题 支持 ActiveRecord 模式：支持 ActiveRecord 形式调用，实体类只需继承 Model 类即可进行强大的 CRUD 操作 支持自定义全局通用操作：支持全局通用方法注入（ Write once, use anywhere ） 内置代码生成器：采用代码或者 Maven 插件可快速生成 Mapper 、 Model 、 Service 、Controller 层代码，支持模板引擎，更有超多自定义配置等您来使用 内置分页插件：基于 MyBatis 物理分页，开发者无需关心具体操作，配置好插件之后，写分页等同于普通 List 查询 分页插件支持多种数据库：支持 MySQL、MariaDB、Oracle、DB2、H2、HSQL、SQLite、Postgre、SQLServer 等多种数据库 内置性能分析插件：可输出 SQL 语句以及其执行时间，建议开发测试时启用该功能，能快速揪出慢查询 内置全局拦截插件：提供全表 delete 、 update 操作智能分析阻断，也可自定义拦截规则，预防误操作"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-12-04T09:34:46.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"MyBatis"}],["meta",{"property":"article:published_time","content":"2021-09-10T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-12-04T09:34:46.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"MyBatis-Plus（一）\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2021-09-10T00:00:00.000Z\\",\\"dateModified\\":\\"2023-12-04T09:34:46.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"一、MyBatis-Plus简介","slug":"一、mybatis-plus简介","link":"#一、mybatis-plus简介","children":[{"level":3,"title":"1、简介","slug":"_1、简介","link":"#_1、简介","children":[]},{"level":3,"title":"2、特性","slug":"_2、特性","link":"#_2、特性","children":[]},{"level":3,"title":"3、支持数据库","slug":"_3、支持数据库","link":"#_3、支持数据库","children":[]},{"level":3,"title":"4、框架结构","slug":"_4、框架结构","link":"#_4、框架结构","children":[]},{"level":3,"title":"5、代码及文档地址","slug":"_5、代码及文档地址","link":"#_5、代码及文档地址","children":[]}]},{"level":2,"title":"二、入门案例","slug":"二、入门案例","link":"#二、入门案例","children":[{"level":3,"title":"1、开发环境","slug":"_1、开发环境","link":"#_1、开发环境","children":[]},{"level":3,"title":"2、创建数据库及表","slug":"_2、创建数据库及表","link":"#_2、创建数据库及表","children":[]},{"level":3,"title":"3、创建Spring Boot工程","slug":"_3、创建spring-boot工程","link":"#_3、创建spring-boot工程","children":[]},{"level":3,"title":"4、编写代码","slug":"_4、编写代码","link":"#_4、编写代码","children":[]}]},{"level":2,"title":"三、基本CRUD","slug":"三、基本crud","link":"#三、基本crud","children":[{"level":3,"title":"1、BaseMapper","slug":"_1、basemapper","link":"#_1、basemapper","children":[]},{"level":3,"title":"2、插入","slug":"_2、插入","link":"#_2、插入","children":[]},{"level":3,"title":"3、删除","slug":"_3、删除","link":"#_3、删除","children":[]},{"level":3,"title":"4、修改","slug":"_4、修改","link":"#_4、修改","children":[]},{"level":3,"title":"5、查询","slug":"_5、查询","link":"#_5、查询","children":[]},{"level":3,"title":"6、自定义功能","slug":"_6、自定义功能","link":"#_6、自定义功能","children":[]},{"level":3,"title":"7、通用Service","slug":"_7、通用service","link":"#_7、通用service","children":[]}]},{"level":2,"title":"四、常用注解","slug":"四、常用注解","link":"#四、常用注解","children":[{"level":3,"title":"1、@TableName","slug":"_1、-tablename","link":"#_1、-tablename","children":[]},{"level":3,"title":"2、@TableId","slug":"_2、-tableid","link":"#_2、-tableid","children":[]},{"level":3,"title":"3、@TableField","slug":"_3、-tablefield","link":"#_3、-tablefield","children":[]},{"level":3,"title":"4、@TableLogic","slug":"_4、-tablelogic","link":"#_4、-tablelogic","children":[]}]}],"git":{"createdTime":1701682486000,"updatedTime":1701682486000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":19.44,"words":5833},"filePathRelative":"框架/持久层/03-MyBatis-Plus（一）.md","localizedDate":"2021年9月10日","excerpt":"<h1> MyBatis-Plus（一）</h1>\\n<h2> 一、MyBatis-Plus简介</h2>\\n<h3> 1、简介</h3>\\n<p>MyBatis-Plus（简称 MP）是一个 MyBatis的增强工具，在 MyBatis 的基础上只做增强不做改变，为简化开发、提高效率而生。</p>\\n<p>愿景</p>\\n<p>我们的愿景是成为 MyBatis 最好的搭档，就像魂斗罗中的 1P、2P，基友搭配，效率翻倍</p>\\n<h3> 2、特性</h3>\\n<ul>\\n<li><strong>无侵入</strong>：只做增强不做改变，引入它不会对现有工程产生影响，如丝般顺滑</li>\\n<li><strong>损耗小</strong>：启动即会自动注入基本 CURD，性能基本无损耗，直接面向对象操作</li>\\n<li><strong>强大的 CRUD 操作</strong>：内置通用 Mapper、通用 Service，仅仅通过少量配置即可实现单表大部分CRUD 操作，更有强大的条件构造器，满足各类使用需求</li>\\n<li><strong>支持 Lambda 形式调用</strong>：通过 Lambda 表达式，方便的编写各类查询条件，无需再担心字段写错</li>\\n<li><strong>支持主键自动生成</strong>：支持多达 4 种主键策略（内含分布式唯一 ID 生成器 - Sequence），可自由配置，完美解决主键问题</li>\\n<li><strong>支持 ActiveRecord 模式</strong>：支持 ActiveRecord 形式调用，实体类只需继承 Model 类即可进行强大的 CRUD 操作</li>\\n<li><strong>支持自定义全局通用操作</strong>：支持全局通用方法注入（ Write once, use anywhere ）</li>\\n<li><strong>内置代码生成器</strong>：采用代码或者 Maven 插件可快速生成 Mapper 、 Model 、 Service 、Controller 层代码，支持模板引擎，更有超多自定义配置等您来使用</li>\\n<li><strong>内置分页插件</strong>：基于 MyBatis 物理分页，开发者无需关心具体操作，配置好插件之后，写分页等同于普通 List 查询</li>\\n<li><strong>分页插件支持多种数据库</strong>：支持 MySQL、MariaDB、Oracle、DB2、H2、HSQL、SQLite、Postgre、SQLServer 等多种数据库</li>\\n<li><strong>内置性能分析插件</strong>：可输出 SQL 语句以及其执行时间，建议开发测试时启用该功能，能快速揪出慢查询</li>\\n<li><strong>内置全局拦截插件</strong>：提供全表 delete 、 update 操作智能分析阻断，也可自定义拦截规则，预防误操作</li>\\n</ul>","autoDesc":true}');export{e as data};
